function factorial(n) {
  if (n === 0) {
    return 1;
  } else {
    return n * factorial(n - 1);
  }
}

console.log(factorial(5));  // console.logで '120' を表示

function sumArray(array) {
  let sum = 0;
  array.forEach(function(item) {
    sum += item;
  });
  console.log(sum);
}

sumArray([1, 2, 3, 4, 5]);  // console.logで '15' を表示

function transformArray(array, callback) {
  return array.map(callback);
}

function double(n) {
  return n * 2;
}

console.log(transformArray([1, 2, 3, 4, 5], double));  // console.logで '[2, 4, 6, 8, 10]' を表示

function printName(obj) {
  console.log(obj.name);
}

printName({name: 'Alice', age: 25});  // console.logで 'Alice' を表示

function double(n = 10) {
  return n * 2;
}

console.log(double());  // console.logで '20' を表示

function sum(...nums) {
  let total = 0;
  for(let n of nums) {
    total += n;
  }
  console.log(total);
}

sum(3, 5, 7);  // console.logで '15' を表示

function reverseArgs(a, b, c) {
  return [c, b, a];
}

console.log(reverseArgs(1, 2, 3));  // console.logで '[3, 2, 1]' を表示

function printObj(obj) {
  console.log(obj);
}

printObj({ name: 'John', age: 25 });  // console.logで '{ name: 'John', age: 25 }' を表示

function defaultArgs(x = 10, y = 20) {
  console.log(x * y);
}

defaultArgs();  // console.logで '200' を表示

function add(x, y, z) {
  if (z === undefined) {
    console.log(x + y);
  } else {
    console.log(x * y * z);
  }
}

add(1, 2);  // console.logで '3' を表示
add(1, 2, 3);  // console.logで '6' を表示

